// Process YoY Data  (REPLACE with this version that outputs a YoY table pack)

const currentData = $('Excel: Get Current Period').first().json;
const previousData = $('Excel: Get Previous Period').first().json;

function safeNum(x) {
  const n = Number(x);
  return Number.isFinite(n) ? n : 0;
}

function pct(a, b) {
  if (!b) return null;
  return (a / b) * 100;
}

function fmtInt(x) {
  return Math.round(x).toLocaleString();
}
function fmtMoney0(x) {
  return `£${Math.round(x).toLocaleString()}`;
}
function fmtMoney2(x) {
  return `£${Number(x).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
}
function fmtPct2(x) {
  if (x === null || x === undefined || Number.isNaN(x)) return "";
  return `${Number(x).toFixed(2)}%`;
}
function fmtVar1(x) {
  if (x === null || x === undefined || Number.isNaN(x)) return "";
  const v = Number(x);
  return `${v >= 0 ? "+" : ""}${v.toFixed(1)}%`;
}

function calc(d) {
  const clicks = safeNum(d.clicks);
  const sales = safeNum(d.sales);
  const orderValue = safeNum(d.orderValue);
  const aov = sales ? (orderValue / sales) : 0;

  const pubCommission = safeNum(d.publisherCommission);
  const tdCommission = safeNum(d.tdCommission);
  const totalCommission = pubCommission + tdCommission;

  // If your sheet has cost or spend, map it here; otherwise keep 0
  const cost = safeNum(d.cost ?? d.spend ?? d.mediaCost ?? 0);

  const convRate = clicks ? pct(sales, clicks) : 0;                // %
  const cpa = sales ? (totalCommission / sales) : 0;               // £ per sale (commission CPA)
  const roi = totalCommission ? (orderValue / totalCommission) : 0; // ratio

  return {
    clicks, sales, convRate, orderValue, aov,
    pubCommission, totalCommission,
    cpa, roi
  };
}

const cur = calc(currentData);
const prev = calc(previousData);

function diff(a, b) { return a - b; }
function varPct(a, b) { return b ? ((a - b) / b * 100) : null; }

const rows = [
  {
    Row: "Recent",
    Clicks: fmtInt(cur.clicks),
    Sales: fmtInt(cur.sales),
    "Conv Rate": fmtPct2(cur.convRate),
    "Order value": fmtMoney0(cur.orderValue),
    "AOV": fmtMoney2(cur.aov),
    "Publ Commission": fmtMoney0(cur.pubCommission),
    "Total Commission": fmtMoney0(cur.totalCommission),
    "CPA": fmtMoney2(cur.cpa),
    "ROI": cur.roi ? cur.roi.toFixed(2) : ""
  },
  {
    Row: "Previous",
    Clicks: fmtInt(prev.clicks),
    Sales: fmtInt(prev.sales),
    "Conv Rate": fmtPct2(prev.convRate),
    "Order value": fmtMoney0(prev.orderValue),
    "AOV": fmtMoney2(prev.aov),
    "Publ Commission": fmtMoney0(prev.pubCommission),
    "Total Commission": fmtMoney0(prev.totalCommission),
    "CPA": fmtMoney2(prev.cpa),
    "ROI": prev.roi ? prev.roi.toFixed(2) : ""
  },
  {
    Row: "Difference",
    Clicks: (diff(cur.clicks, prev.clicks) >= 0 ? "+" : "") + fmtInt(diff(cur.clicks, prev.clicks)),
    Sales: (diff(cur.sales, prev.sales) >= 0 ? "+" : "") + fmtInt(diff(cur.sales, prev.sales)),
    "Conv Rate": fmtPct2(diff(cur.convRate, prev.convRate)),
    "Order value": (diff(cur.orderValue, prev.orderValue) >= 0 ? "+" : "") + fmtMoney0(diff(cur.orderValue, prev.orderValue)).replace("£", "£"),
    "AOV": fmtMoney2(diff(cur.aov, prev.aov)),
    "Publ Commission": (diff(cur.pubCommission, prev.pubCommission) >= 0 ? "+" : "") + fmtMoney0(diff(cur.pubCommission, prev.pubCommission)).replace("£", "£"),
    "Total Commission": (diff(cur.totalCommission, prev.totalCommission) >= 0 ? "+" : "") + fmtMoney0(diff(cur.totalCommission, prev.totalCommission)).replace("£", "£"),
    "CPA": fmtMoney2(diff(cur.cpa, prev.cpa)),
    "ROI": diff(cur.roi, prev.roi).toFixed(2)
  },
  {
    Row: "% Variance",
    Clicks: fmtVar1(varPct(cur.clicks, prev.clicks)),
    Sales: fmtVar1(varPct(cur.sales, prev.sales)),
    "Conv Rate": fmtVar1(varPct(cur.convRate, prev.convRate)),
    "Order value": fmtVar1(varPct(cur.orderValue, prev.orderValue)),
    "AOV": fmtVar1(varPct(cur.aov, prev.aov)),
    "Publ Commission": fmtVar1(varPct(cur.pubCommission, prev.pubCommission)),
    "Total Commission": fmtVar1(varPct(cur.totalCommission, prev.totalCommission)),
    "CPA": fmtVar1(varPct(cur.cpa, prev.cpa)),
    "ROI": fmtVar1(varPct(cur.roi, prev.roi))
  }
];

const dataForAI = `Program YoY Summary Table (Recent vs Previous)\n${JSON.stringify(rows, null, 2)}`;

return [{
  json: {
    dataForAI,
    programYoYTable: rows
  }
}];

// Process Publisher QBR Pack1  (FIX: also output dataForAI for the AI node)
function safeNum(x) {
  const n = Number(x);
  return Number.isFinite(n) ? n : 0;
}

function safePct(x) {
  if (x === null || x === undefined || x === "") return null;
  if (typeof x === "string" && x.trim().endsWith("%")) {
    const v = Number(x.trim().slice(0, -1));
    return Number.isFinite(v) ? v : null;
  }
  const v = Number(x);
  return Number.isFinite(v) ? v : null;
}

function fmtMoney0(x) {
  return `£${Math.round(x).toLocaleString()}`;
}
function fmtInt(x) {
  return Math.round(x).toLocaleString();
}
function fmtYoY(x) {
  if (x === null || x === undefined || Number.isNaN(x)) return "";
  const v = Number(x);
  if (!Number.isFinite(v)) return "";
  return `${v >= 0 ? "+" : ""}${v.toFixed(0)}%`;
}

// --- POC categorisation ---
function inferPublisherType(nameRaw) {
  const name = String(nameRaw || "").toLowerCase();
  if (/(blue light|defence|teachers|carers|charity worker|health service|totum|benifex|telus|perk|benefit|nextjump|perksatwork|studentbeans)/.test(name))
    return "Closed User Groups";
  if (/(cashback|quidco|topcashback|easyfundraising|swagbucks|reward gateway|rakuten|give as you live|vc loyalty|wanteed)/.test(name))
    return "Cashback";
  if (/(voucher|vouchers|codes|coupon|deal|deals|discount|hotukdeals|savoo|wowcher|bravovoucher|latest deals|vouchercloud|purpl|purplee|vouchercodes|voucherbox|netvouchercodes)/.test(name))
    return "Discount & Voucher Sites";
  if (/(css|google shopping|comparison|compare|idealo|redbrain|shoparize|shopia|expandeo|priceplanet|delupe|genie shopping)/.test(name))
    return "CSS";
  if (/(skimlinks|soreto|subnetwork|network|linkhaitao|affilizz|convert)/.test(name))
    return "Subnetworks";
  return "Other";
}

function mapRow(d) {
  return {
    publisher: d.sourceName ?? d.publisher ?? d.Publisher ?? "Unknown",

    ov: safeNum(d.orderValue ?? d.ov ?? d.OV),
    ovYoY: safePct(d.orderValueYoY ?? d.ovYoY ?? d["OV YoY"]),

    sales: safeNum(d.sales ?? d.Sales),
    salesYoY: safePct(d.salesYoY ?? d["Sales YoY"]),

    clicks: safeNum(d.clicks ?? d.Clicks),
    clicksYoY: safePct(d.clicksYoY ?? d["Clicks YoY"]),
  };
}

const rows = $input.all().map(i => i.json).map(mapRow);

const enriched = rows.map(r => ({
  ...r,
  publisherType: inferPublisherType(r.publisher),
}));

const byType = new Map();
for (const r of enriched) {
  if (!byType.has(r.publisherType)) byType.set(r.publisherType, []);
  byType.get(r.publisherType).push(r);
}

const orderedTypes = [
  "Closed User Groups",
  "Cashback",
  "Discount & Voucher Sites",
  "CSS",
  "Subnetworks",
  "Other",
];

const packs = [];

for (const type of orderedTypes) {
  const pubs = byType.get(type) || [];
  if (!pubs.length) continue;

  const top = [...pubs].sort((a, b) => b.ov - a.ov).slice(0, 12);

  const totals = top.reduce((a, r) => {
    a.ov += r.ov;
    a.sales += r.sales;
    a.clicks += r.clicks;
    return a;
  }, { ov: 0, sales: 0, clicks: 0 });

  const tableRows = top.map(r => ({
    Publisher: r.publisher,
    "OV": fmtMoney0(r.ov),
    "OV YoY": fmtYoY(r.ovYoY),
    "Sales": fmtInt(r.sales),
    "Sales YoY": fmtYoY(r.salesYoY),
    "Clicks": fmtInt(r.clicks),
    "Clicks YoY": fmtYoY(r.clicksYoY),
  }));

  packs.push({
    publisherType: type,
    totals: {
      OV: fmtMoney0(totals.ov),
      Sales: fmtInt(totals.sales),
      Clicks: fmtInt(totals.clicks),
    },
    tableRows,
  });
}

return [{
  json: {
    publisherTypeTables: packs,
    dataForAI: JSON.stringify(packs, null, 2)
  }
}];

// Build Final Response1  (USE THIS)

const program = $json.programOutput || "(No program analysis returned)";
const programYoYTable = $json.programYoYTable || [];

const publisherAnalysis = $json.publisherAnalysis || "(No publisher analysis returned)";
const tables = $json.publisherTables || [];

function mdTable(rows) {
  if (!rows || !rows.length) return "(no rows)";
  const headers = Object.keys(rows[0]);
  const sep = headers.map(() => "---");
  return [
    `| ${headers.join(" | ")} |`,
    `| ${sep.join(" | ")} |`,
    ...rows.map(r => `| ${headers.map(h => String(r[h] ?? "")).join(" | ")} |`)
  ].join("\n");
}

const programTableMd = mdTable(programYoYTable);

const publisherTablesMd = tables.map(t =>
  `### ${t.publisherType}\n` +
  `Totals: OV ${t.totals.OV} | Sales ${t.totals.Sales} | Clicks ${t.totals.Clicks}\n\n` +
  mdTable(t.tableRows)
).join("\n\n---\n\n");

return [{
  json: {
    output:
`## Program YoY Analysis
${program}

### YoY Summary Table
${programTableMd}

---

## Publisher Performance by Type
${publisherAnalysis}

---

## Publisher Tables
${publisherTablesMd || "(No publisher tables)"}`
  }
}];

// Tag Program Output  (UPDATE to also pass the table)
return [{
  json: {
    programOutput: $json.output ?? "",
    programYoYTable: $node["Process YoY Data"].json.programYoYTable ?? []
  }
}];

// Tag Publisher Output  (FIX: pass BOTH analysis + tables)
return [{
  json: {
    publisherAnalysis: $json.output ?? "",
    publisherTables: $node["Process Publisher QBR Pack1"].json.publisherTypeTables ?? []
  }
}];

// Fan-out context node
// Connect this node to BOTH branches (program YoY + publisher QBR)

const incomingText =
  $json?.message?.text ??
  $json?.chatInput ??
  $json?.text ??
  "";

// For now, always run both branches
return [
  {
    json: {
      incomingText,
      runProgram: true,
      runPublisher: true
    }
  }
];
